// Reviews Component
const Reviews = () => {
  const scrollRef = useRef<HTMLDivElement>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [startX, setStartX] = useState(0);
  const [scrollLeft, setScrollLeft] = useState(0);
  const [isPaused, setIsPaused] = useState(false);

  const reviewImages = Array.from({ length: 12 }, (_, i) => 
    `https://raw.githubusercontent.com/faaaroooq22/menu-mrbeefburgrz/refs/heads/main/r${i + 1}.png`
  );

  useEffect(() => {
    const scrollContainer = scrollRef.current;
    if (!scrollContainer) return;

    let animationFrameId: number;
    let autoScrollPos = scrollContainer.scrollLeft;
    const speed = 0.5;

    const step = () => {
      if (!isPaused && !isDragging && scrollContainer) {
        autoScrollPos += speed;
        if (autoScrollPos >= scrollContainer.scrollWidth / 2) {
            autoScrollPos = 0;
            scrollContainer.scrollLeft = 0;
        } else {
            scrollContainer.scrollLeft = autoScrollPos;
        }
      } else if (scrollContainer) {
         autoScrollPos = scrollContainer.scrollLeft;
      }
      animationFrameId = requestAnimationFrame(step);
    };

    animationFrameId = requestAnimationFrame(step);
    return () => cancelAnimationFrame(animationFrameId);
  }, [isPaused, isDragging]);

  const handleMouseDown = (e: React.MouseEvent) => {
    setIsDragging(true);
    setIsPaused(true);
    setStartX(e.pageX - (scrollRef.current?.offsetLeft || 0));
    setScrollLeft(scrollRef.current?.scrollLeft || 0);
  };

  const handleMouseLeave = () => {
    setIsDragging(false);
    setIsPaused(false);
  };

  const handleMouseUp = () => {
    setIsDragging(false);
    setTimeout(() => setIsPaused(false), 100); 
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging) return;
    e.preventDefault();
    const x = e.pageX - (scrollRef.current?.offsetLeft || 0);
    const walk = (x - startX) * 2;
    if (scrollRef.current) {
      scrollRef.current.scrollLeft = scrollLeft - walk;
    }
  };

  return (
    <section className="py-20 bg-[#0a0a0a] overflow-hidden relative">
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-gray-800/20 via-transparent to-transparent opacity-50"></div>

        <div className="container mx-auto px-4 mb-12 text-center reveal relative z-10">
            <h2 className="font-bebas text-5xl sm:text-7xl font-extrabold text-white mb-2 tracking-wide drop-shadow-xl">
                <span className="text-yellow-500">5 STAR</span> RATINGS
            </h2>
            <div className="flex items-center justify-center gap-2 text-yellow-500 mb-6">
              {[...Array(5)].map((_, i) => <Star key={i} className="w-8 h-8 fill-current drop-shadow-lg" />)}
            </div>
            <p className="text-gray-400 text-lg max-w-2xl mx-auto font-light">Real people. Real taste. Real feedback.</p>
        </div>

        <div className="relative w-full reveal group">
            <div className="absolute left-0 top-0 bottom-0 w-12 md:w-32 bg-gradient-to-r from-[#0a0a0a] to-transparent z-10 pointer-events-none"></div>
            <div className="absolute right-0 top-0 bottom-0 w-12 md:w-32 bg-gradient-to-l from-[#0a0a0a] to-transparent z-10 pointer-events-none"></div>

            <div 
                ref={scrollRef}
                className="flex overflow-x-auto no-scrollbar cursor-grab active:cursor-grabbing items-center py-8 transform-gpu" 
                onMouseDown={handleMouseDown}
                onMouseLeave={handleMouseLeave}
                onMouseUp={handleMouseUp}
                onMouseMove={handleMouseMove}
                onTouchStart={() => setIsPaused(true)}
                onTouchEnd={() => setTimeout(() => setIsPaused(false), 500)}
            >
                {[...reviewImages, ...reviewImages, ...reviewImages].map((src, idx) => (
                    <div key={`review-${idx}`} className="flex-shrink-0 w-[350px] sm:w-[500px] mx-4 sm:mx-8 transform transition-transform duration-300 hover:scale-[1.02]">
                        <div className="bg-gray-800 border border-gray-700 rounded-3xl overflow-hidden shadow-2xl select-none">
                             <img 
                                src={src} 
                                alt={`Customer Review`} 
                                className="w-full h-auto object-contain block pointer-events-none" 
                                loading="lazy"
                             />
                        </div>
                    </div>
                ))}
            </div>
        </div>

        <div className="mt-16 flex flex-col sm:flex-row items-center justify-center gap-6 px-4 reveal">
            <a href="https://share.google/1CyGTKVsewqwHnSgr" target="_blank" rel="noreferrer" className="w-full sm:w-auto flex items-center justify-center gap-3 px-10 py-4 bg-transparent hover:bg-white/5 text-gray-300 hover:text-white border-2 border-gray-700 rounded-full transition-all duration-300 group font-bold tracking-wider">
                <ExternalLink className="w-5 h-5 group-hover:scale-110 transition-transform" />
                VIEW ALL 100+ REVIEWS
            </a>
            <a href="https://g.page/r/CT-o8k1bI1GdEAE/review" target="_blank" rel="noreferrer" className="w-full sm:w-auto flex items-center justify-center gap-3 px-10 py-4 bg-yellow-500 hover:bg-yellow-400 text-black rounded-full font-bold shadow-[0_0_20px_rgba(234,179,8,0.3)] hover:shadow-[0_0_30px_rgba(234,179,8,0.5)] transition-all duration-300 transform hover:-translate-y-1">
                <MessageSquarePlus className="w-5 h-5" />
                REVIEW US
            </a>
        </div>
    </section>
  );
};

const App: React.FC = () => {
  const [menuItems, setMenuItems] = useState<MenuItem[]>(() => {
    const saved = localStorage.getItem('mrbeef_menu_v1');
    return saved ? JSON.parse(saved) : STATIC_MENU_ITEMS;
  });

  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [showScrollTop, setShowScrollTop] = useState(false);
  const [currentView, setCurrentView] = useState<'home' | 'menu' | 'deals' | 'make-burger' | 'admin'>('home');

  // Modal State
  const [optionModalOpen, setOptionModalOpen] = useState(false);
  const [currentOptionItem, setCurrentOptionItem] = useState<MenuItem | null>(null);
  const [currentOptions, setCurrentOptions] = useState<string[]>([]);
  const [modalSelectionMode, setModalSelectionMode] = useState<'single' | 'multiple'>('multiple');

  useEffect(() => {
    localStorage.setItem('mrbeef_menu_v1', JSON.stringify(menuItems));
  }, [menuItems]);

  useEffect(() => {
    const handleScroll = () => {
        if (window.scrollY > 300) setShowScrollTop(true);
        else setShowScrollTop(false);
    };
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleNavigate = (view: 'home' | 'menu' | 'deals' | 'admin', hash?: string) => {
    setCurrentView(view);
    if (view === 'home' && hash) {
        setTimeout(() => {
            const element = document.querySelector(hash);
            if (element) {
                const headerOffset = 100;
                const elementPosition = element.getBoundingClientRect().top;
                const offsetPosition = elementPosition + window.pageYOffset - headerOffset;
                window.scrollTo({ top: offsetPosition, behavior: "smooth" });
            }
        }, 100);
    } else {
        window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const triggerHaptic = () => {
    if (typeof navigator !== 'undefined' && navigator.vibrate) navigator.vibrate(50);
  };

  const handleAddToCartClick = (item: MenuItem) => {
    if (item.id === 'a5') {
        setCurrentOptionItem(item);
        setCurrentOptions(['Garlic', 'Chipotle', 'Toumiya', 'Honey Mustard', 'Hot Jalapeño', 'Barbecue', 'Chef\'s Signature']);
        setModalSelectionMode('multiple');
        setOptionModalOpen(true);
        return;
    }
    if (item.id === 'd1') {
        setCurrentOptionItem(item);
        setCurrentOptions(['7up', 'Pepsi']);
        setModalSelectionMode('multiple');
        setOptionModalOpen(true);
        return;
    }
    if (item.id === 'b2' || item.id === 'b3') {
        setCurrentOptionItem(item);
        setCurrentOptions(['Grilled Onion', 'Raw Onion']);
        setModalSelectionMode('single');
        setOptionModalOpen(true);
        return;
    }
    triggerHaptic();
    addToCart(item);
  };

  const handleOptionConfirm = (selections: { option: string; quantity: number }[]) => {
    if (!currentOptionItem) return;
    triggerHaptic();
    selections.forEach(sel => {
        const variantItem = {
            ...currentOptionItem,
            id: `${currentOptionItem.id}-${sel.option}`, 
            name: `${currentOptionItem.name} (${sel.option})`,
        };
        addToCart(variantItem, sel.quantity);
    });
  };

  const addToCart = (item: MenuItem, quantity: number = 1) => {
    setCartItems(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + quantity } : i);
      }
      return [...prev, { ...item, quantity: quantity }];
    });
  };

  const removeFromCart = (id: string) => {
    setCartItems(prev => prev.filter(i => i.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCartItems(prev => prev.map(i => {
      if (i.id === id) return { ...i, quantity: Math.max(1, i.quantity + delta) };
      return i;
    }));
  };

  const totalItems = cartItems.reduce((acc, item) => acc + item.quantity, 0);
  const totalAmount = cartItems.reduce((acc, item) => acc + (item.price * item.quantity), 0);

  const socialLinks = [
      { name: "Instagram", icon: Instagram, href: "https://www.instagram.com/mr.beefburgrz?igsh=bW5xZm43bmR6Ymsw" },
      { name: "Facebook", icon: Facebook, href: "https://www.facebook.com/share/1A5ejXApa7/" },
      { name: "YouTube", icon: Youtube, href: "https://youtube.com/@mrbeefburgrz?si=vQ-h8ygT5oiEFdEo" },
      { name: "TikTok", icon: TikTokIcon, href: "https://www.tiktok.com/@mrbeefburgrz?_r=1&_t=ZS-91N9HD5GTdx" },
      { name: "LinkedIn", icon: Linkedin, href: "https://www.linkedin.com/company/mr-beef-burgrz/" },
  ];

  const contactLinks = [
      { name: "Call Us", icon: Phone, href: "tel:+923240460398" },
      { name: "WhatsApp", icon: MessageCircle, href: "https://wa.me/message/GCCQJTH6ZQF6O1" },
      { name: "Email", icon: Mail, href: "mailto:mr.beefburgrz@gmail.com" },
      { name: "Location", icon: MapPin, href: "https://maps.app.goo.gl/Y4brSsZDP2oCEQKTA" },
  ];

  const reviewLinks = [
      { name: "Google", icon: Globe, href: "https://share.google/X5gPvzd9rOTctx9bN" },
      { name: "Review Us", icon: Star, href: "https://g.page/r/CT-o8k1bI1GdEAE/review" },
      { name: "Check Reviews", icon: Share2, href: "https://share.google/1CyGTKVsewqwHnSgr" },
  ];

  if (currentView === 'admin') {
      return (
        <AdminPanel 
            menuItems={menuItems} 
            setMenuItems={setMenuItems} 
            onExit={() => setCurrentView('home')} 
        />
      );
  }

  return (
    <div className="min-h-screen text-gray-100 relative flex flex-col">
      <div className="fixed inset-0 -z-50 h-full w-full bg-[#111111]">
        <div className="absolute left-0 right-0 top-0 -z-10 m-auto h-[310px] w-[310px] rounded-full bg-red-600 opacity-20 blur-[100px]"></div>
      </div>

      {currentView !== 'make-burger' && (
          <Navbar 
            cartCount={totalItems} 
            onOpenCart={() => setIsCartOpen(true)}
            onNavigate={(view, hash) => handleNavigate(view as any, hash)}
            currentView={currentView === 'home' ? 'home' : (currentView === 'deals' ? 'deals' : 'home')}
          />
      )}

      <Cart 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)} 
        items={cartItems} 
        onRemove={removeFromCart}
        onUpdateQuantity={updateQuantity}
      />

      <OptionModal 
        isOpen={optionModalOpen}
        onClose={() => setOptionModalOpen(false)}
        item={currentOptionItem}
        options={currentOptions}
        selectionType={modalSelectionMode}
        onConfirm={handleOptionConfirm}
      />

      <main className="flex-grow">
        {currentView === 'home' ? (
          <>
            <Hero onOrderNowClick={() => setCurrentView('menu')} />

            {/* Dedicated View Full Menu Section */}
            <div className="flex flex-col items-center justify-center py-12 sm:py-20 bg-gradient-to-b from-transparent to-black/40 border-b border-gray-800/30">
                <button 
                    onClick={() => setCurrentView('menu')}
                    className="bg-red-600 hover:bg-red-500 text-white font-bebas text-2xl sm:text-5xl px-10 sm:px-16 py-4 sm:py-6 rounded-full shadow-[0_0_30px_rgba(220,38,38,0.4)] hover:shadow-[0_0_60px_rgba(220,38,38,0.7)] transition-all duration-300 transform hover:scale-105 active:scale-95 flex items-center gap-5 group border-2 border-red-500/30"
                >
                    <Utensils className="w-6 h-6 sm:w-10 h-10 group-hover:rotate-12 transition-transform" />
                    VIEW FULL MENU
                </button>
                <div className="mt-10 flex gap-3 sm:gap-6 overflow-hidden px-4">
                     {['#Juicy', '#Smash', '#PureBeef', '#MalirSpecial'].map(tag => (
                         <span key={tag} className="text-gray-500 text-[10px] sm:text-sm font-bold tracking-widest uppercase border border-gray-800 px-4 py-1.5 rounded-full bg-black/20">{tag}</span>
                     ))}
                </div>
            </div>

            <section id="about" className="py-12 sm:py-32 bg-black/20 scroll-mt-20">
                <div className="w-full px-4 md:px-8">
                    <h2 className="font-bebas text-4xl sm:text-6xl text-center font-extrabold text-yellow-500 mb-8 sm:mb-16 tracking-wider reveal drop-shadow-lg">
                        OUR PROMISE
                    </h2>
                    <div className="grid md:grid-cols-2 gap-8 lg:gap-24 items-center reveal">
                        <div className="relative rounded-2xl sm:rounded-3xl overflow-hidden shadow-2xl p-6 sm:p-8 bg-yellow-500 flex items-center justify-center h-full min-h-[300px] sm:min-h-[500px] transform rotate-1 hover:rotate-0 transition-transform duration-500 border-2 sm:border-4 border-yellow-600">
                            <img
                                src="https://raw.githubusercontent.com/faaaroooq22/menu-mrbeefburgrz/refs/heads/main/cow2.png"
                                alt="100% Pure Beef"
                                className="w-2/3 h-auto object-contain drop-shadow-2xl animate-float-slow"
                            />
                            <p className="absolute bottom-4 sm:bottom-6 text-gray-900 font-bebas text-xl sm:text-3xl tracking-widest text-center w-full px-2">100% Pure smashed Beef with 80/20</p>
                        </div>
                        <div className="space-y-4 sm:space-y-6 text-sm sm:text-lg text-gray-200 text-justify bg-black/40 p-6 sm:p-12 rounded-2xl border border-gray-800 backdrop-blur-sm">
                            <p className="italic text-yellow-500 font-semibold text-base sm:text-xl leading-relaxed">
