                                We believe great food starts with passion and ends with satisfaction. That’s why our team focuses on maintaining premium standards, hygiene, and freshness in every single order.
                            </p>
                        </div>
                    </div>
                </div>
            </section>

            <Reviews />
          </>
        ) : currentView === 'menu' ? (
           <Menu menuItems={menuItems} onAddToCart={handleAddToCartClick} onBack={() => setCurrentView('home')} />
        ) : currentView === 'deals' ? (
          <Deals onBack={() => handleNavigate('home')} />
        ) : (
            <MakeYourBurger 
                onBack={() => handleNavigate('home')} 
                onAddToCart={(item) => {
                    triggerHaptic();
                    addToCart(item);
                }} 
            />
        )}
      </main>

      {currentView !== 'make-burger' && (
      <footer id="contact" className="bg-[#050505] border-t border-gray-800 pt-20 pb-10 reveal scroll-mt-28 relative mt-auto">
         <div className="w-full px-6 md:px-12 max-w-8xl mx-auto">
             <div className="flex flex-col lg:flex-row justify-between gap-12 mb-16">
                 <div className="lg:w-1/2 w-full">
                     <h3 className="font-bebas text-5xl sm:text-7xl text-white mb-6 tracking-wide drop-shadow-md">
