                 <div id="social" className="lg:w-auto lg:min-w-[450px]">
                     <div className="mb-10">
                         <h4 className="font-bold text-white text-lg mb-6 uppercase tracking-wider">Social Media</h4>
                         <div className="flex gap-4 flex-wrap">
                            {socialLinks.map((link) => (
                                <a key={link.name} href={link.href} target="_blank" rel="noreferrer" className="w-12 h-12 flex items-center justify-center rounded-full bg-gray-800 hover:bg-white text-gray-400 hover:text-black transition-all duration-300 hover:scale-110">
                                    <link.icon className="w-6 h-6" />
                                </a>
                            ))}
                         </div>
