interface MenuProps {
  menuItems: MenuItem[];
  onAddToCart: (item: MenuItem) => void;
  onBack: () => void;
}

export const Menu: React.FC<MenuProps> = ({ menuItems, onAddToCart, onBack }) => {
  const categories = Array.from(new Set(menuItems.map(item => item.category)));
  const scrollRef = useRef<HTMLDivElement>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [startX, setStartX] = useState(0);
  const [scrollLeft, setScrollLeft] = useState(0);

  const handleMouseDown = (e: React.MouseEvent) => {
    setIsDragging(true);
    setStartX(e.pageX - (scrollRef.current?.offsetLeft || 0));
    setScrollLeft(scrollRef.current?.scrollLeft || 0);
  };

  const handleMouseLeave = () => setIsDragging(false);
  const handleMouseUp = () => setIsDragging(false);

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging) return;
    e.preventDefault();
    const x = e.pageX - (scrollRef.current?.offsetLeft || 0);
    const walk = (x - startX) * 2;
    if (scrollRef.current) scrollRef.current.scrollLeft = scrollLeft - walk;
  };

  const scrollNav = (direction: 'left' | 'right') => {
    if (scrollRef.current) {
        const scrollAmount = 200;
        scrollRef.current.scrollBy({
            left: direction === 'left' ? -scrollAmount : scrollAmount,
            behavior: 'smooth'
        });
    }
  };

  const scrollToSection = (id: string) => {
    const element = document.getElementById(id);
    if (element) {
        const offset = 250; 
        const bodyRect = document.body.getBoundingClientRect().top;
        const elementRect = element.getBoundingClientRect().top;
        const elementPosition = elementRect - bodyRect;
        const offsetPosition = elementPosition - offset;
        window.scrollTo({ top: offsetPosition, behavior: 'smooth' });
    }
  };

  const getContainerId = (category: string) => {
      if (category === 'Chicken Broast') return 'sec-broast';
      if (category === 'Snacks') return 'sec-snacks';
      if (category.includes('Fries')) return 'sec-fries';
      if (category === 'Drinks') return 'sec-drinks';
      if (category === 'Add-ons') return 'sec-addons';
      return undefined;
  };

  const getSubcategorySectionId = (category: string, subcategory: string) => {
      if (category === 'House of Beef') {
          if (subcategory.includes('Classic')) return 'sec-classic-beef';
          if (subcategory.includes('Premium')) return 'sec-premium-beef';
      }
      if (category === 'House of Chicken') {
           if (subcategory.includes('Zingsters')) return 'sec-zingsters';
           if (subcategory.includes('Flame')) return 'sec-grilled';
      }
      return undefined;
  };

  return (
    <section id="menu" className="pb-10 sm:pb-20 pt-6 border-b border-red-700/30 scroll-mt-20 relative min-h-screen">

      {/* Back Arrow Button - Shifted down significantly on mobile to clear the expanded category navigation header */}
      <button 
        onClick={onBack}
        className="fixed top-64 sm:top-28 left-4 sm:left-6 z-[60] group p-3 bg-black/60 backdrop-blur-xl border border-white/20 rounded-full hover:bg-white/10 hover:border-yellow-500 transition-all duration-300 shadow-[0_0_30px_rgba(0,0,0,0.6)] active:scale-95"
        aria-label="Back to Home"
      >
         <ArrowLeft className="w-6 h-6 text-white group-hover:text-yellow-500 transition-transform duration-300 group-hover:-translate-x-1" />
      </button>

      <div className="w-full px-2 sm:px-8 mt-16 sm:mt-10">
        <h2 className="font-bebas text-4xl sm:text-5xl text-center text-red-500 mb-8 sm:mb-10 tracking-wider reveal drop-shadow-md leading-tight">
          MENU <br className="sm:hidden" /> <span className="font-sans font-normal italic text-gray-200 text-lg sm:text-3xl block sm:inline mt-1 sm:mt-0">Pick anything, it’s all special</span>
        </h2>
      </div>

      <div className="sticky top-[112px] md:top-24 z-40 bg-[#111111] mb-12 pt-6 pb-3 transition-all duration-300 border-b border-gray-800/50">
        <div className="max-w-7xl mx-auto relative group px-2 sm:px-8">
            <div className="absolute left-0 top-0 bottom-0 w-8 bg-gradient-to-r from-[#111111] to-transparent z-10 pointer-events-none md:hidden"></div>
            <div className="absolute right-0 top-0 bottom-0 w-8 bg-gradient-to-l from-[#111111] to-transparent z-10 pointer-events-none md:hidden"></div>
            <button onClick={() => scrollNav('left')} className="absolute left-1 md:-left-4 top-1/2 -translate-y-1/2 z-20 bg-gray-900/90 p-1.5 sm:p-2 rounded-full border border-gray-700 text-yellow-500 hover:bg-gray-800 shadow-xl flex items-center justify-center transition-all hover:scale-110 active:scale-95" aria-label="Scroll Left">
                <ChevronLeft className="w-5 h-5 sm:w-6 sm:h-6" />
            </button>
            <div ref={scrollRef} className="flex gap-4 sm:gap-6 overflow-x-auto no-scrollbar pt-4 pb-2 px-6 sm:px-4 scroll-smooth cursor-grab active:cursor-grabbing select-none items-center" onMouseDown={handleMouseDown} onMouseLeave={handleMouseLeave} onMouseUp={handleMouseUp} onMouseMove={handleMouseMove}>
                {NAV_ITEMS.map((item, idx) => (
                    <button key={idx} onClick={() => scrollToSection(item.targetId)} className="flex flex-col items-center gap-2 min-w-[80px] sm:min-w-[100px] group transition-transform duration-300 hover:-translate-y-1" style={{ animationDelay: `${idx * 0.2}s` }}>
                        <div className="w-14 h-14 sm:w-16 sm:h-16 rounded-2xl border flex items-center justify-center bg-gray-900 relative overflow-hidden animate-border-glow transition-all duration-300">
                            <item.icon className="w-7 h-7 sm:w-8 sm:h-8 text-yellow-500 drop-shadow-[0_0_5px_rgba(234,179,8,0.5)]" />
                        </div>
                        <span className="text-[9px] sm:text-[10px] font-bold text-gray-400 group-hover:text-yellow-500 whitespace-nowrap transition-colors uppercase tracking-widest bg-gray-900/80 px-2 py-0.5 rounded-full border border-transparent group-hover:border-gray-800">
                            {item.label}
                        </span>
                    </button>
                ))}
            </div>
            <button onClick={() => scrollNav('right')} className="absolute right-1 md:-right-4 top-1/2 -translate-y-1/2 z-20 bg-gray-900/90 p-1.5 sm:p-2 rounded-full border border-gray-700 text-yellow-500 hover:bg-gray-800 shadow-xl flex items-center justify-center transition-all hover:scale-110 active:scale-95" aria-label="Scroll Right">
                <ChevronRight className="w-5 h-5 sm:w-6 sm:h-6" />
            </button>
        </div>
      </div>

      <div className="w-full px-2 sm:px-8">
        <div className="space-y-8 sm:space-y-12 max-w-7xl mx-auto">
          {categories.map((category) => {
            const categoryItems = menuItems.filter(item => item.category === category);
            const subcategories = Array.from(new Set(categoryItems.map(item => item.subcategory || 'General')));
            const borderColor = category === 'House of Chicken' || category.includes('Snacks') || category.includes('Drinks') || category.includes('Add-ons') ? 'border-yellow-500/40' : 'border-red-700/40';
            const titleColor = category === 'House of Chicken' || category.includes('Snacks') || category.includes('Drinks') || category.includes('Add-ons') ? 'text-red-500' : 'text-yellow-500';
            const containerIdVal = getContainerId(category);

            return (
              <div key={category} id={containerIdVal} className={`bg-gray-900/50 p-3 sm:p-6 rounded-2xl sm:rounded-3xl shadow-xl border-2 sm:border-4 ${borderColor} reveal scroll-mt-32`}>
                <h3 className={`text-2xl sm:text-4xl font-bold ${titleColor} mb-4 sm:mb-6 font-bebas tracking-wide uppercase text-center sm:text-left`}>{category}</h3>
                {subcategories.map(subcategory => {
                  const items = categoryItems.filter(item => (item.subcategory || 'General') === subcategory);
                  const showSubheader = subcategory !== 'General';
                  const sectionId = !containerIdVal ? getSubcategorySectionId(category, subcategory) : undefined;
                  return (
                    <div key={subcategory} id={sectionId} className="mb-6 sm:mb-8 last:mb-0 scroll-mt-40">
                      {showSubheader && (
                        <h4 className={`text-base sm:text-2xl font-semibold border-b pb-1 sm:pb-2 mb-3 sm:mb-4 ${category === 'House of Chicken' ? 'text-yellow-400 border-yellow-500' : 'text-red-400 border-red-700'}`}>
                          {subcategory}
                        </h4>
                      )}
                      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-2 sm:gap-6 items-stretch">
                        {items.map((item) => (
                          <div 
                            key={item.id}
                            onClick={() => onAddToCart(item)}
                            className="group relative flex flex-col justify-between p-2.5 sm:p-4 rounded-xl border border-gray-800 bg-gray-800 hover:bg-gray-700 transition-all duration-200 cursor-pointer select-none reveal h-full tap-highlight-transparent shadow-lg hover:shadow-xl hover:-translate-y-1 active:scale-95 transform-gpu"
                          >
                            <div className="flex flex-col h-full pointer-events-none">
                              <span className={`font-bold text-sm sm:text-lg leading-tight mb-2 ${category === 'House of Chicken' ? 'text-red-400' : 'text-yellow-400'}`}>
                                {item.name}
                              </span>
                              <span className="text-[10px] sm:text-sm text-gray-400 leading-tight group-hover:text-gray-200 transition-colors mb-4">
                                {item.description}
                              </span>
                              <div className="mt-auto flex justify-between items-end w-full pt-2">
                                <span className={`text-sm sm:text-xl font-extrabold whitespace-nowrap ${category === 'House of Chicken' ? 'text-yellow-500' : 'text-red-500'}`}>
                                  {item.price}/-
                                </span>
                                <div className="bg-green-600 text-white p-1.5 sm:p-2 rounded-full shadow-lg group-hover:bg-green-500 group-hover:scale-110 transition-all">
                                    <Plus className="w-3 h-3 sm:w-5 sm:h-5" />
                                </div>
                              </div>
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  );
                })}
              </div>
            );
          })}
        </div>
      </div>
    </section>
  );
}

import React, { useState } from 'react';
