interface AdminPanelProps {
  menuItems: MenuItem[];
  setMenuItems: React.Dispatch<React.SetStateAction<MenuItem[]>>;
  onExit: () => void;
}

export const AdminPanel: React.FC<AdminPanelProps> = ({ menuItems, setMenuItems, onExit }) => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'items' | 'categories'>('dashboard');
  const [editingItem, setEditingItem] = useState<MenuItem | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [notification, setNotification] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  const categories = Array.from(new Set(menuItems.map(i => i.category)));

  const showNotification = (message: string, type: 'success' | 'error' = 'success') => {
    setNotification({ message, type });
    setTimeout(() => setNotification(null), 3000);
  };

  const handleSaveItem = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const itemData: any = {
      id: editingItem?.id || `item-${Date.now()}`,
      name: formData.get('name') as string,
      description: formData.get('description') as string,
      price: parseInt(formData.get('price') as string),
      category: formData.get('category') as string,
      subcategory: formData.get('subcategory') as string || undefined,
      isPopular: formData.get('isPopular') === 'on',
    };

    if (editingItem) {
      setMenuItems(prev => prev.map(i => i.id === editingItem.id ? itemData : i));
      showNotification('Item updated successfully');
    } else {
      setMenuItems(prev => [...prev, itemData]);
      showNotification('Item added successfully');
    }
    setEditingItem(null);
    setIsAdding(false);
  };

  const handleDeleteItem = (id: string) => {
    if (confirm('Are you sure you want to delete this item?')) {
      setMenuItems(prev => prev.filter(i => i.id !== id));
      showNotification('Item deleted');
    }
  };

  const handleAddCategory = () => {
    const name = prompt('Enter new category name:');
    if (name && !categories.includes(name)) {
      // Categories are derived from items, so we just add a placeholder or let the user know they can use it now
      showNotification(`Category "${name}" is now available to use for items.`);
    }
  };

  return (
    <div className="min-h-screen bg-[#050505] text-gray-100 flex flex-col font-inter">
      {/* Top Bar */}
      <div className="bg-gray-950 border-b border-gray-800 px-6 py-4 flex items-center justify-between sticky top-0 z-50">
        <div className="flex items-center gap-4">
          <button onClick={onExit} className="p-2 hover:bg-gray-800 rounded-full text-gray-400 hover:text-white transition-all">
            <ArrowLeft className="w-6 h-6" />
          </button>
          <div>
            <h1 className="text-xl font-bebas tracking-widest text-yellow-500 leading-none">Admin Panel</h1>
            <p className="text-[10px] text-gray-500 uppercase font-bold">Mr. Beef Burgrz Manager</p>
          </div>
        </div>
        <div className="flex gap-2">
            <button 
                onClick={() => { setIsAdding(true); setEditingItem(null); }} 
                className="bg-red-600 hover:bg-red-500 text-white px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 shadow-lg"
            >
                <Plus className="w-4 h-4" />
                ADD ITEM
            </button>
        </div>
      </div>

      <div className="flex flex-1 overflow-hidden">
        {/* Sidebar Nav */}
        <aside className="w-20 md:w-64 border-r border-gray-800 bg-gray-950 flex flex-col pt-6">
           <nav className="flex-1 space-y-1 px-3">
              {[
                { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
                { id: 'items', label: 'Manage Items', icon: Utensils },
                { id: 'categories', label: 'Categories', icon: Tag },
              ].map(tab => (
                <button 
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id as any)}
                  className={`w-full flex items-center gap-4 px-4 py-3 rounded-xl transition-all ${
                    activeTab === tab.id ? 'bg-yellow-500 text-black shadow-lg shadow-yellow-500/10' : 'text-gray-400 hover:bg-gray-900 hover:text-white'
                  }`}
                >
                  <tab.icon className="w-5 h-5 flex-shrink-0" />
                  <span className="hidden md:block font-bold text-sm">{tab.label}</span>
                </button>
              ))}
           </nav>
        </aside>

