                             <span className="px-2 py-1 bg-gray-800 text-gray-400 text-[10px] font-bold rounded uppercase">{item.category}</span>
                          </td>
                          <td className="px-6 py-4 font-mono font-bold text-yellow-500">{item.price}/-</td>
                          <td className="px-6 py-4 text-right">
                             <div className="flex justify-end gap-2">
                               <button onClick={() => setEditingItem(item)} className="p-2 text-gray-500 hover:text-white hover:bg-gray-700 rounded-lg transition-all"><Edit3 className="w-4 h-4" /></button>
                               <button onClick={() => handleDeleteItem(item.id)} className="p-2 text-gray-500 hover:text-red-500 hover:bg-red-500/10 rounded-lg transition-all"><Trash2 className="w-4 h-4" /></button>
                             </div>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
               </div>
            </div>
          )}

          {activeTab === 'categories' && (
             <div className="animate-in fade-in slide-in-from-right-4">
                <div className="flex justify-between items-center mb-6">
                  <h2 className="text-2xl font-bebas tracking-wide">Category Management</h2>
                  <button onClick={handleAddCategory} className="bg-gray-800 hover:bg-gray-700 text-white px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2">
                     <Plus className="w-4 h-4" />
                     NEW CATEGORY
                  </button>
                </div>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                  {categories.map(cat => (
                    <div key={cat} className="bg-gray-900 border border-gray-800 p-6 rounded-2xl flex items-center justify-between group">
                       <div className="flex items-center gap-3">
                         <div className="w-10 h-10 bg-yellow-500/10 text-yellow-500 rounded-xl flex items-center justify-center">
                           <Tag className="w-5 h-5" />
                         </div>
                         <div>
                           <h4 className="font-bold text-gray-200">{cat}</h4>
                           <span className="text-xs text-gray-500">{menuItems.filter(i => i.category === cat).length} Items</span>
                         </div>
                       </div>
                       <button className="opacity-0 group-hover:opacity-100 p-2 text-gray-500 hover:text-white transition-all"><ChevronRight className="w-5 h-5" /></button>
                    </div>
                  ))}
                </div>
             </div>
          )}
        </main>
      </div>

      {/* Editor Modal */}
      {(editingItem || isAdding) && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/90 backdrop-blur-md" onClick={() => {setEditingItem(null); setIsAdding(false);}}></div>
          <div className="bg-gray-900 border border-gray-800 w-full max-w-xl rounded-2xl shadow-2xl relative z-10 animate-in zoom-in-95 overflow-hidden">
             <div className="bg-gray-950 px-6 py-4 border-b border-gray-800 flex justify-between items-center">
               <h3 className="font-bebas text-xl text-yellow-500">{editingItem ? 'EDIT ITEM' : 'ADD NEW ITEM'}</h3>
               <button onClick={() => {setEditingItem(null); setIsAdding(false);}} className="text-gray-500 hover:text-white transition-colors"><X className="w-6 h-6" /></button>
             </div>
             <form onSubmit={handleSaveItem} className="p-6 space-y-4">
                <div className="grid grid-cols-2 gap-4">
                  <div className="col-span-2">
                    <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">Item Name</label>
                    <input name="name" defaultValue={editingItem?.name} required className="w-full bg-gray-800 border border-gray-700 rounded-lg p-3 text-white focus:border-yellow-500 outline-none" placeholder="e.g. Classic Smash" />
                  </div>
                  <div className="col-span-2">
                    <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">Description</label>
                    <textarea name="description" defaultValue={editingItem?.description} required className="w-full bg-gray-800 border border-gray-700 rounded-lg p-3 text-white focus:border-yellow-500 outline-none h-20 resize-none" placeholder="Details about the ingredients..." />
                  </div>
                  <div>
                    <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">Price (PKR)</label>
                    <input name="price" type="number" defaultValue={editingItem?.price} required className="w-full bg-gray-800 border border-gray-700 rounded-lg p-3 text-white focus:border-yellow-500 outline-none" />
                  </div>
                  <div>
                    <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">Category</label>
                    <select name="category" defaultValue={editingItem?.category || categories[0]} required className="w-full bg-gray-800 border border-gray-700 rounded-lg p-3 text-white focus:border-yellow-500 outline-none appearance-none">
                       {categories.map(cat => <option key={cat} value={cat}>{cat}</option>)}
                    </select>
                  </div>
                  <div>
                    <label className="block text-[10px] font-bold text-gray-500 uppercase mb-1">Subcategory (Optional)</label>
                    <input name="subcategory" defaultValue={editingItem?.subcategory} className="w-full bg-gray-800 border border-gray-700 rounded-lg p-3 text-white focus:border-yellow-500 outline-none" placeholder="e.g. Smash Burgers" />
                  </div>
                  <div className="flex items-center gap-3 bg-gray-800 border border-gray-700 rounded-lg px-4">
                     <input type="checkbox" name="isPopular" defaultChecked={editingItem?.isPopular} className="w-4 h-4 accent-yellow-500" id="isPopular" />
                     <label htmlFor="isPopular" className="text-xs text-gray-400 font-bold uppercase cursor-pointer">Popular Item</label>
                  </div>
                </div>
                <div className="pt-4 flex gap-3">
                   <button type="submit" className="flex-1 bg-yellow-500 hover:bg-yellow-400 text-black font-bold py-3 rounded-xl flex items-center justify-center gap-2 transition-all">
                      <Save className="w-5 h-5" />
                      SAVE ITEM
                   </button>
                   <button type="button" onClick={() => {setEditingItem(null); setIsAdding(false);}} className="px-6 py-3 bg-gray-800 text-white font-bold rounded-xl border border-gray-700">CANCEL</button>
                </div>
             </form>
          </div>
        </div>
      )}

      {/* Notifications */}
      {notification && (
        <div className="fixed bottom-6 right-6 z-[110] animate-in slide-in-from-right-10">
           <div className={`px-6 py-3 rounded-xl border shadow-2xl flex items-center gap-3 ${
             notification.type === 'success' ? 'bg-green-500/10 border-green-500 text-green-500' : 'bg-red-500/10 border-red-500 text-red-500'
           }`}>
             <CheckCircle2 className="w-5 h-5" />
             <span className="font-bold text-sm tracking-wide">{notification.message}</span>
           </div>
        </div>
      )}
    </div>
  );
};

import React, { useRef, useState } from 'react';
